import React, { useState } from 'react';
import { UserProfile, UserGoal, ActivityLevel } from '../types';

interface OnboardingProps {
  onComplete: (profile: UserProfile) => void;
}

const Onboarding: React.FC<OnboardingProps> = ({ onComplete }) => {
  const [formData, setFormData] = useState({
    name: '',
    age: 25,
    weight: 70,
    height: 175,
    gender: 'male' as const,
    goal: UserGoal.MAINTENANCE,
    activityLevel: ActivityLevel.MODERATE
  });

  const calculateTargets = () => {
    // Basic BMR calculation (Mifflin-St Jeor)
    let bmr = 10 * formData.weight + 6.25 * formData.height - 5 * formData.age;
    bmr = formData.gender === 'male' ? bmr + 5 : bmr - 161;

    // Activity Multiplier
    const multipliers = {
      [ActivityLevel.SEDENTARY]: 1.2,
      [ActivityLevel.LIGHT]: 1.375,
      [ActivityLevel.MODERATE]: 1.55,
      [ActivityLevel.VERY]: 1.725,
      [ActivityLevel.EXTREME]: 1.9
    };

    let tdee = bmr * multipliers[formData.activityLevel];

    // Goal adjustments
    if (formData.goal === UserGoal.FAT_LOSS) tdee -= 500;
    if (formData.goal === UserGoal.MUSCLE_GAIN || formData.goal === UserGoal.WEIGHT_GAIN) tdee += 300;

    // Macros distribution
    const protein = formData.weight * 2; // 2g per kg
    const fat = (tdee * 0.25) / 9; // 25% of calories
    const carbs = (tdee - (protein * 4 + fat * 9)) / 4;

    return {
      dailyCalorieTarget: Math.round(tdee),
      macroTargets: {
        protein: Math.round(protein),
        carbs: Math.round(carbs),
        fat: Math.round(fat)
      }
    };
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const targets = calculateTargets();
    onComplete({
      ...formData,
      ...targets
    });
  };

  return (
    <div className="max-w-md mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="text-center">
        <h1 className="text-3xl font-extrabold text-slate-900 mb-2">Welcome to NuVision AI</h1>
        <p className="text-slate-500">Let's personalize your nutrition journey.</p>
      </div>

      <form onSubmit={handleSubmit} className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 space-y-4">
        <div>
          <label className="block text-sm font-semibold text-slate-700 mb-1">Your Name</label>
          <input
            type="text"
            required
            className="w-full px-4 py-2 rounded-xl border border-slate-200 focus:ring-2 focus:ring-emerald-500 outline-none transition-all"
            value={formData.name}
            onChange={(e) => setFormData({ ...formData, name: e.target.value })}
            placeholder="John Doe"
          />
        </div>

        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-1">Age</label>
            <input
              type="number"
              className="w-full px-4 py-2 rounded-xl border border-slate-200 focus:ring-2 focus:ring-emerald-500 outline-none"
              value={formData.age}
              onChange={(e) => setFormData({ ...formData, age: Number(e.target.value) })}
            />
          </div>
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-1">Gender</label>
            <select
              className="w-full px-4 py-2 rounded-xl border border-slate-200 focus:ring-2 focus:ring-emerald-500 outline-none"
              value={formData.gender}
              onChange={(e) => setFormData({ ...formData, gender: e.target.value as any })}
            >
              <option value="male">Male</option>
              <option value="female">Female</option>
              <option value="other">Other</option>
            </select>
          </div>
        </div>

        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-1">Weight (kg)</label>
            <input
              type="number"
              className="w-full px-4 py-2 rounded-xl border border-slate-200 focus:ring-2 focus:ring-emerald-500 outline-none"
              value={formData.weight}
              onChange={(e) => setFormData({ ...formData, weight: Number(e.target.value) })}
            />
          </div>
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-1">Height (cm)</label>
            <input
              type="number"
              className="w-full px-4 py-2 rounded-xl border border-slate-200 focus:ring-2 focus:ring-emerald-500 outline-none"
              value={formData.height}
              onChange={(e) => setFormData({ ...formData, height: Number(e.target.value) })}
            />
          </div>
        </div>

        <div>
          <label className="block text-sm font-semibold text-slate-700 mb-1">Fitness Goal</label>
          <select
            className="w-full px-4 py-2 rounded-xl border border-slate-200 focus:ring-2 focus:ring-emerald-500 outline-none"
            value={formData.goal}
            onChange={(e) => setFormData({ ...formData, goal: e.target.value as UserGoal })}
          >
            {Object.values(UserGoal).map((g) => (
              <option key={g} value={g}>{g}</option>
            ))}
          </select>
        </div>

        <div>
          <label className="block text-sm font-semibold text-slate-700 mb-1">Activity Level</label>
          <select
            className="w-full px-4 py-2 rounded-xl border border-slate-200 focus:ring-2 focus:ring-emerald-500 outline-none"
            value={formData.activityLevel}
            onChange={(e) => setFormData({ ...formData, activityLevel: e.target.value as ActivityLevel })}
          >
            {Object.values(ActivityLevel).map((a) => (
              <option key={a} value={a}>{a}</option>
            ))}
          </select>
        </div>

        <button
          type="submit"
          className="w-full bg-emerald-600 text-white font-bold py-3 rounded-xl hover:bg-emerald-700 transition-colors shadow-md shadow-emerald-200"
        >
          Start My Journey
        </button>
      </form>
    </div>
  );
};

export default Onboarding;

import React from 'react';
import { UserProfile, MealLog } from '../types';
import { PieChart, Pie, Cell, ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip } from 'recharts';
import { GOAL_COLORS } from '../constants';
import { TrendingUp, Clock, Flame } from 'lucide-react';

interface DashboardProps {
  profile: UserProfile;
  logs: MealLog[];
}

const Dashboard: React.FC<DashboardProps> = ({ profile, logs }) => {
  // Filter logs for today
  const today = new Date().setHours(0, 0, 0, 0);
  const todaysLogs = logs.filter(l => l.timestamp >= today);

  const consumed = todaysLogs.reduce((acc, log) => ({
    calories: acc.calories + log.data.calories,
    protein: acc.protein + log.data.protein,
    carbs: acc.carbs + log.data.carbs,
    fat: acc.fat + log.data.fat,
  }), { calories: 0, protein: 0, carbs: 0, fat: 0 });

  const macroData = [
    { name: 'Protein', value: consumed.protein, target: profile.macroTargets.protein, color: '#10b981' },
    { name: 'Carbs', value: consumed.carbs, target: profile.macroTargets.carbs, color: '#3b82f6' },
    { name: 'Fat', value: consumed.fat, target: profile.macroTargets.fat, color: '#f59e0b' },
  ];

  const calPercentage = Math.min(Math.round((consumed.calories / profile.dailyCalorieTarget) * 100), 100);

  return (
    <div className="space-y-6 animate-in fade-in duration-700">
      <div className="flex justify-between items-end">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Hello, {profile.name}!</h2>
          <p className="text-slate-500 text-sm">Target: {profile.goal}</p>
        </div>
        <div className="text-right">
          <p className="text-xs font-semibold text-slate-400 uppercase">Daily Streak</p>
          <div className="flex items-center gap-1 text-orange-500 font-bold">
            <Flame size={18} fill="currentColor" />
            <span>12 Days</span>
          </div>
        </div>
      </div>

      {/* Progress Cards */}
      <div className="grid grid-cols-1 gap-4">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 relative overflow-hidden">
          <div className="flex justify-between items-start relative z-10">
            <div>
              <p className="text-sm font-semibold text-slate-500 mb-1">Calorie Budget</p>
              <h3 className="text-3xl font-black text-slate-900">
                {consumed.calories} <span className="text-lg font-normal text-slate-400">/ {profile.dailyCalorieTarget} kcal</span>
              </h3>
            </div>
            <div className={`p-2 rounded-lg ${calPercentage > 90 ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>
              <TrendingUp size={20} />
            </div>
          </div>
          <div className="mt-4 w-full bg-slate-100 h-2.5 rounded-full overflow-hidden">
            <div 
              className={`h-full transition-all duration-500 rounded-full ${calPercentage > 90 ? 'bg-rose-500' : 'bg-emerald-500'}`}
              style={{ width: `${calPercentage}%` }}
            />
          </div>
        </div>

        <div className="grid grid-cols-3 gap-3">
          {macroData.map((macro) => (
            <div key={macro.name} className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 text-center">
              <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">{macro.name}</p>
              <p className="text-lg font-bold text-slate-800">{macro.value}g</p>
              <div className="w-full bg-slate-50 h-1.5 rounded-full mt-2">
                <div 
                  className="h-full rounded-full"
                  style={{ width: `${Math.min((macro.value / macro.target) * 100, 100)}%`, backgroundColor: macro.color }}
                />
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Recent Activity */}
      <div>
        <div className="flex justify-between items-center mb-4">
          <h4 className="font-bold text-slate-800">Today's Meals</h4>
          <span className="text-xs text-slate-400 font-medium">{todaysLogs.length} logged</span>
        </div>

        <div className="space-y-3">
          {todaysLogs.length === 0 ? (
            <div className="bg-slate-100 border border-dashed border-slate-300 rounded-2xl p-8 text-center">
              <p className="text-slate-500 text-sm">No meals logged yet. Use the camera to start!</p>
            </div>
          ) : (
            todaysLogs.map((log) => (
              <div key={log.id} className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex items-center gap-4">
                <div className="w-16 h-16 rounded-xl bg-slate-100 overflow-hidden flex-shrink-0">
                  {log.imageUrl ? (
                    <img src={log.imageUrl} alt={log.data.itemName} className="w-full h-full object-cover" />
                  ) : (
                    <div className="w-full h-full flex items-center justify-center text-slate-300">
                      <Clock size={24} />
                    </div>
                  )}
                </div>
                <div className="flex-1 min-w-0">
                  <div className="flex justify-between items-start">
                    <h5 className="font-bold text-slate-900 truncate">{log.data.itemName}</h5>
                    <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full border ${GOAL_COLORS[log.data.goalScore]}`}>
                      {log.data.goalScore}
                    </span>
                  </div>
                  <div className="flex gap-3 mt-1 text-xs text-slate-500">
                    <span>🔥 {log.data.calories} kcal</span>
                    <span>🥩 {log.data.protein}g</span>
                  </div>
                </div>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useRef, useCallback } from 'react';
import { Camera, Upload, RefreshCw, CheckCircle2, AlertTriangle, Search, Info } from 'lucide-react';
import { analyzeFoodImage, analyzeLabelImage } from '../geminiService';
import { UserProfile, MealLog, FoodAnalysisResult, LabelAnalysisResult } from '../types';
import { GOAL_COLORS } from '../constants';

interface ScannerProps {
  profile: UserProfile;
  onLog: (log: MealLog) => void;
}

const Scanner: React.FC<ScannerProps> = ({ profile, onLog }) => {
  const [mode, setMode] = useState<'photo' | 'label'>('photo');
  const [image, setImage] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [foodResult, setFoodResult] = useState<FoodAnalysisResult | null>(null);
  const [labelResult, setLabelResult] = useState<LabelAnalysisResult | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImage(reader.result as string);
        setFoodResult(null);
        setLabelResult(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAnalyze = async () => {
