import React, { useState } from 'react';
import { UserProfile, UserGoal, ActivityLevel } from '../types';

interface ProfileProps {
  profile: UserProfile;
  onUpdate: (profile: UserProfile) => void;
}

const Profile: React.FC<ProfileProps> = ({ profile, onUpdate }) => {
  const [formData, setFormData] = useState(profile);

  const calculateTargets = (data: typeof profile) => {
    let bmr = 10 * data.weight + 6.25 * data.height - 5 * data.age;
    bmr = data.gender === 'male' ? bmr + 5 : bmr - 161;

    const multipliers = {
      [ActivityLevel.SEDENTARY]: 1.2,
      [ActivityLevel.LIGHT]: 1.375,
      [ActivityLevel.MODERATE]: 1.55,
      [ActivityLevel.VERY]: 1.725,
      [ActivityLevel.EXTREME]: 1.9
    };

    let tdee = bmr * multipliers[data.activityLevel];

    if (data.goal === UserGoal.FAT_LOSS) tdee -= 500;
    if (data.goal === UserGoal.MUSCLE_GAIN || data.goal === UserGoal.WEIGHT_GAIN) tdee += 300;

    const protein = data.weight * 2;
    const fat = (tdee * 0.25) / 9;
    const carbs = (tdee - (protein * 4 + fat * 9)) / 4;

    return {
      dailyCalorieTarget: Math.round(tdee),
      macroTargets: {
        protein: Math.round(protein),
        carbs: Math.round(carbs),
        fat: Math.round(fat)
      }
    };
  };

  const handleSave = () => {
    const targets = calculateTargets(formData);
    onUpdate({ ...formData, ...targets });
    alert("Profile updated successfully!");
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center gap-4 p-6 bg-white rounded-3xl shadow-sm border border-slate-100">
        <div className="w-20 h-20 rounded-full bg-emerald-100 flex items-center justify-center text-emerald-600 font-black text-2xl uppercase shadow-inner">
          {profile.name[0]}
        </div>
        <div>
          <h2 className="text-2xl font-bold text-slate-800">{profile.name}</h2>
          <p className="text-slate-500">{profile.goal}</p>
        </div>
      </div>

      <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 space-y-4">
        <h3 className="font-bold text-slate-800">Body Stats</h3>
        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">Weight (kg)</label>
            <input
              type="number"
              className="w-full px-4 py-2 rounded-xl border border-slate-200"
              value={formData.weight}
              onChange={(e) => setFormData({ ...formData, weight: Number(e.target.value) })}
            />
          </div>
          <div>
            <label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">Height (cm)</label>
            <input
              type="number"
              className="w-full px-4 py-2 rounded-xl border border-slate-200"
              value={formData.height}
              onChange={(e) => setFormData({ ...formData, height: Number(e.target.value) })}
            />
          </div>
        </div>

        <div>
          <label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">Current Goal</label>
          <select
            className="w-full px-4 py-2 rounded-xl border border-slate-200"
            value={formData.goal}
            onChange={(e) => setFormData({ ...formData, goal: e.target.value as UserGoal })}
          >
            {Object.values(UserGoal).map((g) => (
              <option key={g} value={g}>{g}</option>
            ))}
          </select>
        </div>

        <div>
          <label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">Activity Level</label>
          <select
            className="w-full px-4 py-2 rounded-xl border border-slate-200"
            value={formData.activityLevel}
            onChange={(e) => setFormData({ ...formData, activityLevel: e.target.value as ActivityLevel })}
          >
            {Object.values(ActivityLevel).map((a) => (
              <option key={a} value={a}>{a}</option>
            ))}
          </select>
        </div>

        <button
          onClick={handleSave}
          className="w-full bg-slate-900 text-white font-bold py-3 rounded-2xl hover:bg-slate-800 transition-all mt-4"
        >
          Save Changes
        </button>
      </div>

      <div className="bg-emerald-50 p-6 rounded-3xl border border-emerald-100">
        <h3 className="font-bold text-emerald-900 mb-3">Calculated Daily Targets</h3>
        <div className="grid grid-cols-2 gap-4">
          <div className="bg-white p-3 rounded-2xl border border-emerald-100">
            <p className="text-[10px] font-bold text-slate-400 uppercase">Calories</p>
            <p className="text-xl font-black text-emerald-600">{profile.dailyCalorieTarget}</p>
          </div>
          <div className="bg-white p-3 rounded-2xl border border-emerald-100">
            <p className="text-[10px] font-bold text-slate-400 uppercase">Protein</p>
            <p className="text-xl font-black text-emerald-600">{profile.macroTargets.protein}g</p>
          </div>
          <div className="bg-white p-3 rounded-2xl border border-emerald-100">
            <p className="text-[10px] font-bold text-slate-400 uppercase">Carbs</p>
            <p className="text-xl font-black text-emerald-600">{profile.macroTargets.carbs}g</p>
          </div>
          <div className="bg-white p-3 rounded-2xl border border-emerald-100">
            <p className="text-[10px] font-bold text-slate-400 uppercase">Fat</p>
            <p className="text-xl font-black text-emerald-600">{profile.macroTargets.fat}g</p>
          </div>
        </div>
      </div>
    </div>
