              </div>

              <div className="flex items-center gap-4 py-2 border-y border-slate-50">
                <div className="text-center flex-1">
                  <p className="text-2xl font-black text-slate-900">{labelResult.healthScore}</p>
                  <p className="text-[10px] font-bold text-slate-400 uppercase">Health Score</p>
                </div>
              </div>

              {labelResult.riskFlags.length > 0 && (
                <div className="bg-rose-50 p-4 rounded-2xl border border-rose-100">
                  <p className="text-xs font-bold text-rose-800 uppercase mb-2 flex items-center gap-2">
                    <AlertTriangle size={14} /> Red Flags Detected
                  </p>
                  <ul className="space-y-1">
                    {labelResult.riskFlags.map((r, idx) => (
                      <li key={idx} className="text-sm text-rose-700 flex items-start gap-2 font-medium">
                        <div className="mt-1.5 w-1 h-1 rounded-full bg-rose-400 flex-shrink-0" />
                        {r}
                      </li>
                    ))}
                  </ul>
                </div>
              )}

              <div className="space-y-3">
                <p className="text-sm font-bold text-slate-700">Better Alternatives:</p>
                <div className="flex flex-wrap gap-2">
                  {labelResult.alternatives.map((a, idx) => (
                    <span key={idx} className="bg-slate-100 text-slate-600 text-xs font-medium px-3 py-1.5 rounded-full">
                      {a}
                    </span>
                  ))}
                </div>
              </div>

              <button 
                onClick={() => { setImage(null); setLabelResult(null); }}
                className="w-full bg-slate-900 text-white font-bold py-3 rounded-2xl hover:bg-slate-800 transition-all"
              >
                Scan Another Product
              </button>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

