import { GoogleGenAI, Type } from "@google/genai";
import { UserProfile, FoodAnalysisResult, LabelAnalysisResult } from "./types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const FOOD_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    itemName: { type: Type.STRING },
    calories: { type: Type.NUMBER },
    protein: { type: Type.NUMBER },
    carbs: { type: Type.NUMBER },
    fat: { type: Type.NUMBER },
    fiber: { type: Type.NUMBER },
    goalScore: { type: Type.STRING, description: "Good, Moderate, or Bad based on the user's fitness goal" },
    suggestions: { 
      type: Type.ARRAY, 
      items: { type: Type.STRING },
      description: "Portion correction tips like 'Add 20g protein' or 'Reduce oil'" 
    },
    honestyScore: { type: Type.NUMBER, description: "Nutrition quality score from 0-100" },
    needsClarification: { type: Type.BOOLEAN, description: "True if specific details like oil usage or precise portion are unclear from photo alone" },
    clarificationQuestions: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          question: { type: Type.STRING },
          options: { type: Type.ARRAY, items: { type: Type.STRING } }
        },
        required: ["id", "question"]
      }
    }
  },
  required: ["itemName", "calories", "protein", "carbs", "fat", "fiber", "goalScore", "suggestions", "honestyScore"]
};

const LABEL_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    extractedIngredients: { type: Type.ARRAY, items: { type: Type.STRING } },
    riskFlags: { type: Type.ARRAY, items: { type: Type.STRING }, description: "e.g. 'Contains hidden sugars', 'High Palm Oil'" },
    healthScore: { type: Type.NUMBER },
    isUltraProcessed: { type: Type.BOOLEAN },
    alternatives: { type: Type.ARRAY, items: { type: Type.STRING }, description: "Healthier alternatives" }
  },
  required: ["extractedIngredients", "riskFlags", "healthScore", "isUltraProcessed", "alternatives"]
};

export async function analyzeFoodImage(
  base64Image: string, 
  profile: UserProfile, 
  userAnswers?: Record<string, string>
): Promise<FoodAnalysisResult> {
  let prompt = `Analyze this food photo for a person with the goal: ${profile.goal}. 
  Current weight: ${profile.weight}kg, Height: ${profile.height}cm.
  Be extremely strict and precise. If you are unsure about ingredients (e.g., hidden oils, portion depth), set needsClarification to true and ask 1-3 targeted questions.`;

  if (userAnswers) {
    prompt += `\n\nThe user provided the following additional details: ${JSON.stringify(userAnswers)}. Refine your previous estimation based on this info. Be very accurate.`;
  }

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { data: base64Image, mimeType: 'image/jpeg' } },
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: FOOD_SCHEMA
    }
  });

  return JSON.parse(response.text || '{}');
}

export async function analyzeLabelImage(base64Image: string): Promise<LabelAnalysisResult> {
  const prompt = `Perform OCR on this food label/ingredients list. Detect hidden sugars, palm oil, preservatives, and ultra-processed ingredients. Provide a health score (0-100) and healthier alternatives.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { data: base64Image, mimeType: 'image/jpeg' } },
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: LABEL_SCHEMA
    }
  });

  return JSON.parse(response.text || '{}');
}

export async function getCoachInsights(history: any[], profile: UserProfile): Promise<string> {
  const prompt = `As a world-class nutrition coach, analyze this user's meal history: ${JSON.stringify(history)}.
  The user's profile: ${JSON.stringify(profile)}.
  Provide a short, punchy summary of their week:
  1. Protein consistency.
  2. Sugar/Junk patterns.
  3. One specific actionable tip for next week.
  Keep it under 150 words and use Markdown formatting.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt
  });

  return response.text || "No insights available yet. Keep logging your meals!";
}

import React, { useState, useRef } from 'react';
import { Camera, Upload, RefreshCw, CheckCircle2, AlertTriangle, Search, Info, Zap, ChevronRight, HelpCircle } from 'lucide-react';
import { analyzeFoodImage, analyzeLabelImage } from '../geminiService';
import { UserProfile, MealLog, FoodAnalysisResult, LabelAnalysisResult } from '../types';
import { GOAL_COLORS } from '../constants';

interface ScannerProps {
  profile: UserProfile;
  onLog: (log: MealLog) => void;
}

const Scanner: React.FC<ScannerProps> = ({ profile, onLog }) => {
  const [mode, setMode] = useState<'photo' | 'label'>('photo');
  const [image, setImage] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [foodResult, setFoodResult] = useState<FoodAnalysisResult | null>(null);
  const [labelResult, setLabelResult] = useState<LabelAnalysisResult | null>(null);
  const [answers, setAnswers] = useState<Record<string, string>>({});
  const [step, setStep] = useState<'upload' | 'questions' | 'result'>('upload');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImage(reader.result as string);
        setFoodResult(null);
        setLabelResult(null);
        setAnswers({});
        setStep('upload');
      };
      reader.readAsDataURL(file);
    }
  };

  const startAnalysis = async () => {
    if (!image) return;
    setIsAnalyzing(true);
    try {
      const base64Data = image.split(',')[1];
      if (mode === 'photo') {
        const result = await analyzeFoodImage(base64Data, profile);
        if (result.needsClarification && result.clarificationQuestions?.length) {
          setFoodResult(result);
          setStep('questions');
        } else {
          setFoodResult(result);
          setStep('result');
        }
      } else {
        const result = await analyzeLabelImage(base64Data);
        setLabelResult(result);
        setStep('result');
      }
    } catch (error) {
      console.error("Analysis failed", error);
      alert("Failed to analyze image. Please try again.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const refineAnalysis = async () => {
    if (!image) return;
    setIsAnalyzing(true);
    try {
      const base64Data = image.split(',')[1];
      const result = await analyzeFoodImage(base64Data, profile, answers);
      setFoodResult(result);
      setStep('result');
    } catch (error) {
      console.error("Refinement failed", error);
      alert("Failed to refine analysis. Please try again.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleSaveMeal = () => {
    if (foodResult && image) {
      onLog({
        id: Date.now().toString(),
        timestamp: Date.now(),
        type: 'photo',
        data: foodResult,
        imageUrl: image
      });
      reset();
      alert("Meal saved to dashboard!");
    }
  };

  const reset = () => {
    setImage(null);
    setFoodResult(null);
    setLabelResult(null);
    setAnswers({});
    setStep('upload');
  };

  return (
    <div className="space-y-6">
      {/* Mode Selector */}
      {step === 'upload' && (
        <div className="flex bg-white p-1 rounded-2xl border border-slate-200 shadow-sm">
          <button
            onClick={() => { setMode('photo'); reset(); }}
            className={`flex-1 flex items-center justify-center gap-2 py-2.5 rounded-xl font-bold transition-all ${mode === 'photo' ? 'bg-emerald-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            <Camera size={18} />
            <span>Food Photo</span>
          </button>
          <button
            onClick={() => { setMode('label'); reset(); }}
            className={`flex-1 flex items-center justify-center gap-2 py-2.5 rounded-xl font-bold transition-all ${mode === 'label' ? 'bg-emerald-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            <Search size={18} />
            <span>Label Scan</span>
          </button>
        </div>
      )}

      {/* Main UI */}
      {!image ? (
        <div 
          onClick={() => fileInputRef.current?.click()}
          className="aspect-square w-full rounded-3xl border-4 border-dashed border-slate-200 bg-slate-50 flex flex-col items-center justify-center gap-4 cursor-pointer hover:border-emerald-300 hover:bg-emerald-50 transition-all group"
        >
          <div className="p-4 bg-white rounded-full shadow-md group-hover:scale-110 transition-transform">
            <Upload className="text-emerald-600" size={32} />
          </div>
          <div className="text-center">
            <p className="font-bold text-slate-700">Tap to upload or take photo</p>
            <p className="text-xs text-slate-400 mt-1">Supports JPG, PNG</p>
          </div>
          <input 
            type="file" 
            accept="image/*" 
            capture="environment" 
            className="hidden" 
            ref={fileInputRef}
            onChange={handleImageUpload}
          />
        </div>
      ) : (
        <div className="space-y-4">
          {/* Image Preview - Smaller if we are in questions/result mode */}
          <div className={`relative ${step === 'upload' ? 'aspect-square' : 'h-32'} w-full rounded-3xl overflow-hidden shadow-xl border-4 border-white transition-all duration-500`}>
            <img src={image} alt="Preview" className="w-full h-full object-cover" />

            {step === 'upload' && !isAnalyzing && (
              <div className="absolute inset-0 bg-black/20 flex items-center justify-center gap-3">
                <button 
                  onClick={reset}
                  className="bg-white/90 p-3 rounded-full text-rose-600 hover:bg-white transition-colors"
                >
                  <RefreshCw size={24} />
                </button>
                <button 
                  onClick={startAnalysis}
                  className="bg-emerald-600 px-6 py-3 rounded-full text-white font-bold hover:bg-emerald-700 shadow-lg flex items-center gap-2 animate-pulse"
                >
                  <Zap size={20} />
                  Analyze Now
                </button>
              </div>
            )}

            {isAnalyzing && (
              <div className="absolute inset-0 bg-black/60 flex flex-col items-center justify-center text-white gap-4">
                <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-emerald-400"></div>
                <p className="font-bold tracking-wide">NuVision Engine is calculating...</p>
              </div>
            )}
          </div>

          {/* Clarification Step */}
          {step === 'questions' && foodResult?.clarificationQuestions && (
            <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 space-y-6 animate-in slide-in-from-bottom-4 duration-500">
              <div className="flex items-center gap-2 text-emerald-600">
                <HelpCircle size={20} />
                <h3 className="font-bold">Almost there! Help us be more precise:</h3>
              </div>

              <div className="space-y-5">
                {foodResult.clarificationQuestions.map((q) => (
                  <div key={q.id} className="space-y-3">
                    <p className="text-sm font-semibold text-slate-700">{q.question}</p>
                    {q.options ? (
                      <div className="flex flex-wrap gap-2">
                        {q.options.map(opt => (
                          <button
                            key={opt}
                            onClick={() => setAnswers({...answers, [q.id]: opt})}
                            className={`px-4 py-2 rounded-xl text-sm font-medium border transition-all ${answers[q.id] === opt ? 'bg-emerald-600 border-emerald-600 text-white shadow-md' : 'bg-slate-50 border-slate-100 text-slate-600 hover:border-emerald-200'}`}
                          >
                            {opt}
                          </button>
                        ))}
                      </div>
                    ) : (
                      <input
                        type="text"
                        placeholder="Type your answer..."
                        className="w-full px-4 py-2 rounded-xl border border-slate-200 focus:ring-2 focus:ring-emerald-500 outline-none"
                        onChange={(e) => setAnswers({...answers, [q.id]: e.target.value})}
                      />
                    )}
                  </div>
                ))}
              </div>

              <button 
                onClick={refineAnalysis}
                disabled={Object.keys(answers).length < foodResult.clarificationQuestions.length}
                className="w-full bg-emerald-600 disabled:bg-slate-300 text-white font-bold py-4 rounded-2xl hover:bg-emerald-700 shadow-lg shadow-emerald-100 flex items-center justify-center gap-2 transition-all"
              >
                <span>Complete Precise Analysis</span>
                <ChevronRight size={20} />
              </button>
            </div>
          )}

          {/* Result Card */}
          {step === 'result' && (
            <div className="animate-in slide-in-from-bottom-4 duration-500">
              {foodResult && (
                <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 space-y-4">
                  <div className="flex justify-between items-start">
                    <div>
                      <h3 className="text-2xl font-black text-slate-900 leading-tight">{foodResult.itemName}</h3>
                      <div className="flex items-center gap-2 mt-1">
                        <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full border uppercase tracking-wider ${GOAL_COLORS[foodResult.goalScore]}`}>
                          {foodResult.goalScore}
                        </span>
                        <span className="text-xs text-slate-400 font-medium tracking-tight">Precision: {foodResult.honestyScore}/100</span>
                      </div>
                    </div>
                    <div className="text-right">
                      <p className="text-3xl font-black text-emerald-600">{foodResult.calories}</p>
                      <p className="text-[10px] font-bold text-slate-400 uppercase">kcal</p>
                    </div>
                  </div>

                  <div className="grid grid-cols-4 gap-2">
                    {[
                      { label: 'Protein', value: foodResult.protein, color: 'bg-emerald-500' },
                      { label: 'Carbs', value: foodResult.carbs, color: 'bg-blue-500' },
                      { label: 'Fat', value: foodResult.fat, color: 'bg-amber-500' },
                      { label: 'Fiber', value: foodResult.fiber, color: 'bg-purple-500' },
                    ].map(m => (
                      <div key={m.label} className="bg-slate-50 p-2 rounded-xl text-center">
                        <p className="text-[9px] font-bold text-slate-400 uppercase leading-none mb-1">{m.label}</p>
                        <p className="text-sm font-bold text-slate-800">{m.value}g</p>
                        <div className={`h-1 w-full rounded-full mt-1 ${m.color}`} />
                      </div>
                    ))}
                  </div>

                  <div className="bg-emerald-50 p-4 rounded-2xl border border-emerald-100">
                    <p className="text-xs font-bold text-emerald-800 uppercase mb-2 flex items-center gap-2 tracking-wide">
