import React, { useState } from 'react';
import { UserProfile, UserGoal, ActivityLevel } from '../types';
import { Zap, ChevronRight } from 'lucide-react';

interface OnboardingProps {
  onComplete: (profile: UserProfile) => void;
}

const Onboarding: React.FC<OnboardingProps> = ({ onComplete }) => {
  const [formData, setFormData] = useState({
    name: '',
    age: 25,
    weight: 70,
    height: 175,
    gender: 'male' as const,
    goal: UserGoal.MAINTENANCE,
    activityLevel: ActivityLevel.MODERATE
  });

  const calculateTargets = () => {
    // Basic BMR calculation (Mifflin-St Jeor)
    let bmr = 10 * formData.weight + 6.25 * formData.height - 5 * formData.age;
    bmr = formData.gender === 'male' ? bmr + 5 : bmr - 161;

    // Activity Multiplier
    const multipliers = {
      [ActivityLevel.SEDENTARY]: 1.2,
      [ActivityLevel.LIGHT]: 1.375,
      [ActivityLevel.MODERATE]: 1.55,
      [ActivityLevel.VERY]: 1.725,
      [ActivityLevel.EXTREME]: 1.9
    };

    let tdee = bmr * multipliers[formData.activityLevel];

    // Goal adjustments
    if (formData.goal === UserGoal.FAT_LOSS) tdee -= 500;
    if (formData.goal === UserGoal.MUSCLE_GAIN || formData.goal === UserGoal.WEIGHT_GAIN) tdee += 300;

    // Macros distribution
    const protein = formData.weight * 2; // 2g per kg
    const fat = (tdee * 0.25) / 9; // 25% of calories
    const carbs = (tdee - (protein * 4 + fat * 9)) / 4;

    return {
      dailyCalorieTarget: Math.round(tdee),
      macroTargets: {
        protein: Math.round(protein),
        carbs: Math.round(carbs),
        fat: Math.round(fat)
      }
    };
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const targets = calculateTargets();
    onComplete({
      ...formData,
      ...targets
    });
  };

  return (
    <div className="fixed inset-0 bg-black text-white z-[100] overflow-y-auto px-6 py-12 flex flex-col items-center">
      <div className="max-w-md w-full space-y-10 animate-in fade-in zoom-in-95 duration-700">
