          <div className="inline-flex items-center justify-center p-3 bg-emerald-500 rounded-2xl shadow-lg shadow-emerald-500/20 mb-2">
            <Zap size={32} fill="white" className="text-white" />
          </div>
          <h1 className="text-4xl font-black tracking-tight">NuVision AI</h1>
          <p className="text-slate-400 text-lg">The future of personalized nutrition starts here.</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div className="space-y-2">
            <label className="text-sm font-bold text-slate-400 uppercase tracking-widest px-1">Identity</label>
            <input
              type="text"
              required
              className="w-full bg-slate-900/50 border border-slate-800 rounded-2xl px-6 py-4 text-lg focus:ring-2 focus:ring-emerald-500 outline-none transition-all placeholder:text-slate-600"
              value={formData.name}
              onChange={(e) => setFormData({ ...formData, name: e.target.value })}
              placeholder="Enter your name"
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest px-1">Age</label>
              <input
                type="number"
                className="w-full bg-slate-900/50 border border-slate-800 rounded-2xl px-6 py-4 focus:ring-2 focus:ring-emerald-500 outline-none"
                value={formData.age}
                onChange={(e) => setFormData({ ...formData, age: Number(e.target.value) })}
              />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest px-1">Gender</label>
              <select
                className="w-full bg-slate-900/50 border border-slate-800 rounded-2xl px-6 py-4 focus:ring-2 focus:ring-emerald-500 outline-none appearance-none cursor-pointer"
                value={formData.gender}
                onChange={(e) => setFormData({ ...formData, gender: e.target.value as any })}
              >
                <option value="male" className="bg-slate-900">Male</option>
                <option value="female" className="bg-slate-900">Female</option>
                <option value="other" className="bg-slate-900">Other</option>
              </select>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest px-1">Weight (kg)</label>
              <input
                type="number"
                className="w-full bg-slate-900/50 border border-slate-800 rounded-2xl px-6 py-4 focus:ring-2 focus:ring-emerald-500 outline-none"
                value={formData.weight}
                onChange={(e) => setFormData({ ...formData, weight: Number(e.target.value) })}
              />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest px-1">Height (cm)</label>
              <input
                type="number"
                className="w-full bg-slate-900/50 border border-slate-800 rounded-2xl px-6 py-4 focus:ring-2 focus:ring-emerald-500 outline-none"
                value={formData.height}
                onChange={(e) => setFormData({ ...formData, height: Number(e.target.value) })}
              />
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest px-1">Primary Objective</label>
            <div className="grid grid-cols-2 gap-2">
              {Object.values(UserGoal).map((g) => (
                <button
                  key={g}
