import React, { useState, useRef } from 'react';
import { Camera, Upload, RefreshCw, CheckCircle2, AlertTriangle, Search, Info, Zap, ChevronRight, HelpCircle } from 'lucide-react';
import { analyzeFoodImage, analyzeLabelImage } from '../geminiService';
import { UserProfile, MealLog, FoodAnalysisResult, LabelAnalysisResult } from '../types';
import { GOAL_COLORS } from '../constants';

interface ScannerProps {
  profile: UserProfile;
  onLog: (log: MealLog) => void;
  theme: 'light' | 'dark';
}

const Scanner: React.FC<ScannerProps> = ({ profile, onLog, theme }) => {
  const [mode, setMode] = useState<'photo' | 'label'>('photo');
  const [image, setImage] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [foodResult, setFoodResult] = useState<FoodAnalysisResult | null>(null);
  const [labelResult, setLabelResult] = useState<LabelAnalysisResult | null>(null);
  const [answers, setAnswers] = useState<Record<string, string>>({});
  const [step, setStep] = useState<'upload' | 'result'>('upload');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImage(reader.result as string);
        resetState();
      };
      reader.readAsDataURL(file);
    }
  };

  const resetState = () => {
    setFoodResult(null);
    setLabelResult(null);
    setAnswers({});
    setStep('upload');
  };

  const startAnalysis = async () => {
    if (!image) return;
    setIsAnalyzing(true);
    try {
      const base64Data = image.split(',')[1];
      if (mode === 'photo') {
        const result = await analyzeFoodImage(base64Data, profile);
        setFoodResult(result);
        setStep('result');
      } else {
        const result = await analyzeLabelImage(base64Data);
        setLabelResult(result);
        setStep('result');
      }
    } catch (error) {
      console.error("Analysis failed", error);
      alert("Failed to analyze image. Please try again.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const refineAnalysis = async () => {
    if (!image) return;
    setIsAnalyzing(true);
    try {
      const base64Data = image.split(',')[1];
      const result = await analyzeFoodImage(base64Data, profile, answers);
      setFoodResult(result);
      // Stay on result step but with updated data
    } catch (error) {
      console.error("Refinement failed", error);
      alert("Failed to refine analysis. Please try again.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleSaveMeal = () => {
    if (foodResult && image) {
      onLog({
        id: Date.now().toString(),
        timestamp: Date.now(),
        type: 'photo',
        data: foodResult,
        imageUrl: image
      });
      reset();
      alert("Meal saved to dashboard!");
    }
  };

  const reset = () => {
    setImage(null);
    resetState();
  };

  return (
    <div className="space-y-6">
      {/* Mode Selector */}
      {step === 'upload' && (
        <div className={`flex p-1 rounded-2xl border shadow-sm transition-colors duration-300 ${theme === 'dark' ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-200'}`}>
          <button
            onClick={() => { setMode('photo'); reset(); }}
            className={`flex-1 flex items-center justify-center gap-2 py-2.5 rounded-xl font-bold transition-all ${mode === 'photo' ? 'bg-emerald-600 text-white shadow-md' : theme === 'dark' ? 'text-slate-500 hover:bg-slate-800' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            <Camera size={18} />
            <span>Food Photo</span>
          </button>
          <button
            onClick={() => { setMode('label'); reset(); }}
            className={`flex-1 flex items-center justify-center gap-2 py-2.5 rounded-xl font-bold transition-all ${mode === 'label' ? 'bg-emerald-600 text-white shadow-md' : theme === 'dark' ? 'text-slate-500 hover:bg-slate-800' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            <Search size={18} />
            <span>Label Scan</span>
          </button>
        </div>
      )}

      {/* Main UI */}
      {!image ? (
        <div 
          onClick={() => fileInputRef.current?.click()}
          className={`aspect-square w-full rounded-3xl border-4 border-dashed flex flex-col items-center justify-center gap-4 cursor-pointer transition-all group ${theme === 'dark' ? 'bg-slate-900/50 border-slate-800 hover:border-emerald-800 hover:bg-emerald-950/20' : 'bg-slate-50 border-slate-200 hover:border-emerald-300 hover:bg-emerald-50'}`}
        >
          <div className={`p-4 rounded-full shadow-md group-hover:scale-110 transition-transform ${theme === 'dark' ? 'bg-slate-800' : 'bg-white'}`}>
            <Upload className="text-emerald-600" size={32} />
          </div>
          <div className="text-center">
            <p className={`font-bold ${theme === 'dark' ? 'text-slate-300' : 'text-slate-700'}`}>Tap to upload or take photo</p>
            <p className="text-xs text-slate-500 mt-1">Supports JPG, PNG</p>
          </div>
          <input 
            type="file" 
            accept="image/*" 
            capture="environment" 
            className="hidden" 
            ref={fileInputRef}
            onChange={handleImageUpload}
          />
        </div>
      ) : (
        <div className="space-y-4">
          <div className={`relative ${step === 'upload' ? 'aspect-square' : 'h-40'} w-full rounded-3xl overflow-hidden shadow-xl border-4 transition-all duration-500 ${theme === 'dark' ? 'border-slate-800' : 'border-white'}`}>
            <img src={image} alt="Preview" className="w-full h-full object-cover" />

            {step === 'upload' && !isAnalyzing && (
              <div className="absolute inset-0 bg-black/20 flex items-center justify-center gap-3">
                <button 
                  onClick={reset}
                  className="bg-white/90 p-3 rounded-full text-rose-600 hover:bg-white transition-colors shadow-lg"
                >
                  <RefreshCw size={24} />
                </button>
                <button 
                  onClick={startAnalysis}
                  className="bg-emerald-600 px-6 py-3 rounded-full text-white font-bold hover:bg-emerald-700 shadow-xl flex items-center gap-2 animate-pulse"
                >
                  <Zap size={20} />
                  Analyze Now
                </button>
              </div>
            )}

            {isAnalyzing && (
              <div className="absolute inset-0 bg-black/70 flex flex-col items-center justify-center text-white gap-4">
                <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-emerald-400"></div>
                <p className="font-bold tracking-wide">NuVision AI is analyzing...</p>
              </div>
            )}
          </div>

          {/* Result Card */}
          {step === 'result' && (
            <div className="animate-in slide-in-from-bottom-4 duration-500 space-y-4">
              {foodResult && (
                <div className={`p-6 rounded-3xl shadow-sm border space-y-4 transition-colors ${theme === 'dark' ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
                  <div className="flex justify-between items-start">
                    <div>
                      <h3 className={`text-2xl font-black leading-tight ${theme === 'dark' ? 'text-white' : 'text-slate-900'}`}>{foodResult.itemName}</h3>
                      <div className="flex items-center gap-2 mt-1">
                        <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full border uppercase tracking-wider ${GOAL_COLORS[foodResult.goalScore]}`}>
                          {foodResult.goalScore}
                        </span>
                        <span className="text-xs text-slate-500 font-medium tracking-tight">Precision: {foodResult.honestyScore}/100</span>
                      </div>
                    </div>
                    <div className="text-right">
                      <p className="text-3xl font-black text-emerald-500">{foodResult.calories}</p>
                      <p className="text-[10px] font-bold text-slate-500 uppercase">kcal</p>
                    </div>
                  </div>

                  <div className="grid grid-cols-4 gap-2">
                    {[
                      { label: 'Protein', value: foodResult.protein, color: 'bg-emerald-500' },
                      { label: 'Carbs', value: foodResult.carbs, color: 'bg-blue-500' },
                      { label: 'Fat', value: foodResult.fat, color: 'bg-amber-500' },
                      { label: 'Fiber', value: foodResult.fiber, color: 'bg-purple-500' },
                    ].map(m => (
                      <div key={m.label} className={`p-2 rounded-xl text-center transition-colors ${theme === 'dark' ? 'bg-slate-800/50' : 'bg-slate-50'}`}>
