                        <p className={`text-sm font-bold ${theme === 'dark' ? 'text-slate-200' : 'text-slate-800'}`}>{m.value}g</p>
                        <div className={`h-1 w-full rounded-full mt-1 ${m.color}`} />
                      </div>
                    ))}
                  </div>

                  {/* Optional Clarification Section */}
                  {foodResult.needsClarification && foodResult.clarificationQuestions && (
                    <div className={`p-5 rounded-2xl border border-dashed space-y-4 ${theme === 'dark' ? 'bg-slate-950 border-slate-800' : 'bg-slate-50 border-slate-200'}`}>
                      <div className="flex items-center gap-2 text-emerald-500">
