                      <div className="space-y-4">
                        {foodResult.clarificationQuestions.map((q) => (
                          <div key={q.id} className="space-y-2">
                            <p className={`text-xs font-semibold ${theme === 'dark' ? 'text-slate-400' : 'text-slate-600'}`}>{q.question}</p>
                            {q.options ? (
                              <div className="flex flex-wrap gap-2">
                                {q.options.map(opt => (
                                  <button
                                    key={opt}
                                    onClick={() => setAnswers({...answers, [q.id]: opt})}
                                    className={`px-3 py-1.5 rounded-lg text-xs font-medium border transition-all ${answers[q.id] === opt ? 'bg-emerald-600 border-emerald-600 text-white' : theme === 'dark' ? 'bg-slate-900 border-slate-700 text-slate-400' : 'bg-white border-slate-200 text-slate-600'}`}
